local xml = require "lxxml"
local cjson = require "cjson"

local function parse_soap_request(body)
    local parser = xml.new()
    local doc, err = parser:parse(body)
    
    if not doc then
        return nil, "Failed to parse XML: " .. (err or "unknown error")
    end
    
    local soap_envelope = doc:find("/soap:Envelope")
    if not soap_envelope then
        return nil, "Invalid SOAP envelope"
    end
    
    local soap_header = soap_envelope:find("soap:Header")
    local soap_body = soap_envelope:find("soap:Body")
    
    local extracted_data = {
        header = {},
        body = {}
    }
    
    if soap_header then
        for _, child in ipairs(soap_header:children()) do
            local name = child:name()
            local value = child:text()
            extracted_data.header[name] = value
        end
    end
    
    if soap_body then
        for _, child in ipairs(soap_body:children()) do
            local name = child:name()
            local value = child:text()
            extracted_data.body[name] = value
        end
    end
    
    return extracted_data
end

local function process_soap_request()
    local request_body = ngx.req.get_body_data()
    
    if not request_body then
        ngx.status = 400
        ngx.say("No request body")
        ngx.exit(400)
        return
    end
    
    local data, err = parse_soap_request(request_body)
    
    if not data then
        ngx.status = 400
        ngx.say("Invalid SOAP request: " .. err)
        ngx.exit(400)
        return
    end
    
    -- Process extracted data
    local response = {
        status = "success",
        data = data
    }
    
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode(response))
end

process_soap_request()